namespace SpriteKind {
    export const Prop = SpriteKind.create()
    export const Locker = SpriteKind.create()
    export const Distraction = SpriteKind.create()
    export const Fires = SpriteKind.create()
    export const UI = SpriteKind.create()
    export const Battery = SpriteKind.create()
    export const Gift = SpriteKind.create()
}
scene.onOverlapTile(SpriteKind.Player, assets.tile`myTile77`, function (sprite, location) {
    tiles.replaceAllTiles(assets.tile`myTile77`, assets.tile`transparency16`)
    music.play(music.melodyPlayable(music.smallCrash), music.PlaybackMode.InBackground)
    tiles.setWallAt(tiles.getTileLocation(14, 17), false)
    tiles.setWallAt(tiles.getTileLocation(14, 18), false)
    tiles.setWallAt(tiles.getTileLocation(14, 19), false)
})
scene.onOverlapTile(SpriteKind.Player, assets.tile`myTile79`, function (sprite, location) {
    tiles.replaceAllTiles(assets.tile`myTile79`, assets.tile`transparency16`)
    music.play(music.melodyPlayable(music.bigCrash), music.PlaybackMode.InBackground)
})
function Gallery () {
    if (Collectibles == 0) {
        game.showLongText("No Collectibles found!", DialogLayout.Bottom)
        Menu()
    } else {
        Gift1()
    }
}
scene.onOverlapTile(SpriteKind.Player, assets.tile`myTile19`, function (sprite, location) {
    tiles.replaceAllTiles(assets.tile`myTile19`, assets.tile`transparency16`)
    if (SavePoint != 8) {
        music.stopAllSounds()
        Hunting = 0
        CorruptionExists = 0
        sprites.destroy(Corruption)
        sprites.destroy(Pathing)
    }
    if (GoodEnding != 0) {
        Hunting = 0
        CorruptionExists = 0
        sprites.destroy(Corruption)
        sprites.destroy(Pathing)
    }
    sprites.destroyAllSpritesOfKind(SpriteKind.Locker)
    sprites.destroyAllSpritesOfKind(SpriteKind.Distraction)
    for (let value4 of tiles.getTilesByType(assets.tile`myTile15`)) {
        Fire = sprites.create(img`
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            . . . . . . . . . . . . . . . . 
            `, SpriteKind.Fires)
        tiles.placeOnTile(Fire, value4)
        animation.runImageAnimation(
        Fire,
        [img`
            . . . . . . 2 2 . . . . . . . . 
            . . . . 2 . 2 2 2 2 . 2 . . . . 
            . . . . 2 2 2 2 2 2 2 2 . . . . 
            . 2 2 . 2 2 2 2 2 2 2 2 2 2 . . 
            . 2 2 2 2 2 2 2 2 2 2 2 2 . . . 
            . 2 2 2 2 2 2 4 2 2 2 2 2 . . . 
            . 2 2 2 2 4 2 4 4 4 2 2 2 2 . . 
            . 2 2 2 2 4 4 4 4 4 4 2 2 2 . . 
            . 2 2 2 2 4 4 4 4 4 4 2 2 2 . . 
            . 2 2 2 4 4 4 5 4 4 4 4 4 2 . . 
            . 2 2 4 4 4 5 5 5 4 4 5 4 2 2 . 
            2 2 2 4 4 4 5 5 5 5 5 5 4 2 2 . 
            2 2 2 4 4 5 5 5 5 5 5 5 4 2 2 . 
            2 2 2 4 5 5 5 5 5 5 5 4 4 4 2 . 
            2 2 4 4 5 5 5 5 5 5 5 4 4 4 2 2 
            2 2 4 4 4 5 5 5 5 5 5 4 4 4 2 2 
            `,img`
            . . . . . . . . 2 2 . . . . . . 
            . . . . 2 . . 2 2 2 . 2 . . . . 
            . . . . 2 2 . . 2 2 2 2 . . . . 
            . . 2 2 2 2 2 . 2 2 2 2 . 2 . . 
            . . . 2 2 2 2 2 2 2 2 2 2 2 . . 
            . . . 2 2 2 2 2 2 2 2 2 2 . 2 . 
            . . 2 2 2 2 2 4 4 2 2 2 2 2 2 . 
            . . 2 2 2 2 4 4 4 4 2 2 2 2 2 . 
            . . 2 2 2 4 4 4 4 4 2 2 2 2 2 . 
            . . 2 2 4 4 4 4 4 4 4 2 2 2 2 . 
            . 2 2 2 4 4 4 5 4 4 4 4 2 2 2 . 
            . 2 2 2 4 4 5 5 5 4 4 4 2 2 2 2 
            . 2 2 4 4 4 5 5 5 5 4 4 2 2 2 2 
            . 2 2 4 4 5 5 5 5 5 4 4 4 2 2 2 
            2 2 2 4 4 5 5 5 5 5 5 4 4 4 2 2 
            2 2 2 4 5 5 5 5 5 5 5 4 4 4 2 2 
            `],
        100,
        true
        )
    }
    music.play(music.melodyPlayable(music.siren), music.PlaybackMode.InBackground)
    if (SavePoint == 8 && GoodEnding == 0) {
        tiles.setWallAt(tiles.getTileLocation(35, 6), false)
        tiles.setWallAt(tiles.getTileLocation(36, 6), false)
        tiles.setWallAt(tiles.getTileLocation(37, 6), false)
        Corruption.setImage(img`
            . . . . 2 f f f f 2 2 2 2 2 . . 
            . . 2 2 2 d d d d 2 4 4 2 2 . . 
            . . 2 4 2 d d d 2 4 5 5 4 2 2 . 
            . . 4 5 4 d 1 d 1 1 1 5 4 4 2 . 
            . . f d d 5 1 d 1 1 5 d 4 4 2 . 
            . f f d d 5 5 d d 5 5 d d f 2 . 
            . f d d d 5 a d d a 5 d d d f . 
            . f d 2 d 5 a d d a 5 d d d f . 
            . f d 2 2 2 d d d d d 2 2 d f . 
            . f d 2 2 2 2 d d d d 2 2 2 f . 
            . f 2 2 2 2 2 d d d 2 2 4 2 2 . 
            . f 2 4 4 4 2 d d 2 2 4 4 4 2 . 
            . f 4 4 5 4 2 2 d 2 4 4 5 4 2 . 
            . . 4 4 5 4 4 2 2 2 4 5 5 4 . . 
            . . . 5 5 5 4 2 2 4 4 5 5 . . . 
            . . . . . 5 4 4 4 4 5 . . . . . 
            `)
    } else {
        if (SavePoint == 8) {
            tiles.setWallAt(tiles.getTileLocation(3, 13), true)
            tiles.setWallAt(tiles.getTileLocation(4, 13), true)
            tiles.setWallAt(tiles.getTileLocation(5, 13), true)
            tiles.setWallAt(tiles.getTileLocation(6, 13), true)
        }
        timer.after(1500, function () {
            if (SavePoint == 1) {
                game.setDialogTextColor(15)
                game.showLongText("Oh damn.", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Is it dead?", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("Oh, right, no.", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("How?", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("This endoskeleton is strong.", DialogLayout.Bottom)
                game.showLongText("What you did burn, is the suit.", DialogLayout.Bottom)
                game.showLongText("While that is precious, it does help the cause.", DialogLayout.Bottom)
                game.showLongText("Please proceed.", DialogLayout.Bottom)
            } else if (SavePoint == 2) {
                game.setDialogTextColor(15)
                game.showLongText("You made it!", DialogLayout.Bottom)
                game.showLongText("I gotta tell you, I was on the edge of my seat!", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("I've had enough, tell me how to leave!", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("Well, unfortunately...", DialogLayout.Bottom)
                game.showLongText("The only exit is blocked by some flames...", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("I'll just wait here then!", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("It will just come back.", DialogLayout.Bottom)
                game.showLongText("The fires are one-time use.", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Fine. I guess I'll just keep on trucking then.", DialogLayout.Bottom)
            } else if (SavePoint == 3) {
                game.setDialogTextColor(4)
                game.showLongText("Jeez, that was close.", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("GREAT NEWS!!!", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Don't scream at me please.", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("I'm just excited because we are close to the end!", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Finally, some good news.", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("Additionally, I've located a torch in the next room.", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Okay, well that's good.", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("You bet it is!", DialogLayout.Bottom)
                game.showLongText("The bad news is that the lights will get dimmer.", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Well that's not as good.", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("Yeah...", DialogLayout.Bottom)
            } else if (SavePoint == 4) {
                game.setDialogTextColor(15)
                game.showLongText("How we doing?", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("What do you mean 'How we doing'???", DialogLayout.Bottom)
                game.showLongText("Did you not see that amalgamation that just chased me?", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("I didn't see The Corruption in the area,", DialogLayout.Bottom)
                game.showLongText("therefore I wasn't paying attention.", DialogLayout.Bottom)
                game.showLongText("You probably ran into some old suits of ours.", DialogLayout.Bottom)
                game.showLongText("We discarded them after a failed experiment,", DialogLayout.Bottom)
                game.showLongText("but they never discarded us.", DialogLayout.Bottom)
                game.showLongText("Don't worry, you shouldn't have to deal with them again.", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Fine, guess I'll move on then.", DialogLayout.Bottom)
            } else if (SavePoint == 5) {
                game.setDialogTextColor(15)
                game.showLongText("Congrats! You're nearly there!", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Wow, thanks.", DialogLayout.Bottom)
                game.showLongText("I feel so accomplished.", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("Just make your way through the sewers!", DialogLayout.Bottom)
                game.showLongText("The R&D Department is right after it!", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("Ew.", DialogLayout.Bottom)
            } else if (SavePoint == 6) {
                info.setScore(100)
                game.setDialogTextColor(15)
                game.showLongText("You're so close now!", DialogLayout.Bottom)
                game.setDialogTextColor(4)
                game.showLongText("I would ask why you didn't help me back there,", DialogLayout.Bottom)
                game.showLongText("but I'm too tired to ask.", DialogLayout.Bottom)
                game.setDialogTextColor(15)
                game.showLongText("Just keep heading on through my friend,", DialogLayout.Bottom)
                game.showLongText("Ignore any other option you may find.", DialogLayout.Bottom)
                tiles.setWallAt(tiles.getTileLocation(4, 28), false)
                tiles.setWallAt(tiles.getTileLocation(4, 29), false)
                tiles.setWallAt(tiles.getTileLocation(4, 30), false)
            }
            tiles.replaceAllTiles(assets.tile`myTile18`, assets.tile`myTile5`)
        })
    }
})
function RunPathing () {
    tiles.placeOnRandomTile(Pathing, assets.tile`myTile7`)
    if (SavePoint == 1) {
        scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Pathing)), 25)
    } else if (SavePoint == 3) {
        scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Pathing)), 35)
    } else if (SavePoint == 5) {
        scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Pathing)), 24)
    } else if (SavePoint == 8) {
        scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Pathing)), 40)
    }
}
controller.up.onEvent(ControllerButtonEvent.Pressed, function () {
    if (InLocker == 1) {
        InLocker = 0
        sprites.destroyAllSpritesOfKind(SpriteKind.Locker)
        sprites.destroyAllSpritesOfKind(SpriteKind.Distraction)
        Lockers()
        sprites.destroy(LockerOverlay)
        MenuOrGame = 1
        Render.moveWithController(2)
        Reginald.setKind(SpriteKind.Prop)
        pause(750)
        Reginald.setKind(SpriteKind.Player)
    }
})
