sprites.onOverlap(SpriteKind.Player, SpriteKind.Gift, function (sprite, otherSprite) {
    sprites.destroy(otherSprite)
    music.play(music.melodyPlayable(music.powerUp), music.PlaybackMode.InBackground)
    Collectibles += 1
    blockSettings.writeNumber("Collectibles", Collectibles)
    if (SavePoint == 1) {
        blockSettings.writeNumber("Gift1", 1)
        game.showLongText("You got a \"Constantine Plushie\"!", DialogLayout.Bottom)
    } else if (SavePoint == 2) {
        blockSettings.writeNumber("Gift2", 1)
        game.showLongText("You got a \"Constantine Water Bottle\"!", DialogLayout.Bottom)
    } else if (SavePoint == 3) {
        blockSettings.writeNumber("Gift3", 1)
        game.showLongText("You got a \"Sophia Hat\"!", DialogLayout.Bottom)
    } else if (SavePoint == 4) {
        blockSettings.writeNumber("Gift4", 1)
        game.showLongText("You got a \"Crumb Action Figure\"!", DialogLayout.Bottom)
    } else if (SavePoint == 5) {
        blockSettings.writeNumber("Gift5", 1)
        game.showLongText("You got a \"Constantine Poster\"!", DialogLayout.Bottom)
    } else if (SavePoint == 6) {
        blockSettings.writeNumber("Gift6", 1)
        game.showLongText("You got a \"Luna Watch\"!", DialogLayout.Bottom)
    }
    game.showLongText("You can view it in your gallery!", DialogLayout.Bottom)
    if (Collectibles == 6) {
        tiles.setWallAt(tiles.getTileLocation(10, 18), false)
        tiles.setWallAt(tiles.getTileLocation(11, 18), false)
        tiles.setWallAt(tiles.getTileLocation(12, 18), false)
    }
})
