scene.onOverlapTile(SpriteKind.Player, assets.tile`myTile50`, function (sprite, location) {
    tiles.replaceAllTiles(assets.tile`myTile50`, assets.tile`myTile7`)
    tiles.setWallAt(tiles.getTileLocation(2, 3), false)
    tiles.setWallAt(tiles.getTileLocation(3, 3), false)
    tiles.setWallAt(tiles.getTileLocation(4, 3), false)
    tiles.setWallAt(tiles.getTileLocation(5, 3), false)
    tiles.setWallAt(tiles.getTileLocation(6, 3), false)
    tiles.setWallAt(tiles.getTileLocation(7, 3), false)
    tiles.setWallAt(tiles.getTileLocation(8, 3), false)
    tiles.setWallAt(tiles.getTileLocation(9, 3), false)
    music.play(music.melodyPlayable(music.bigCrash), music.PlaybackMode.InBackground)
})
