controller.down.onEvent(ControllerButtonEvent.Pressed, function () {
    if (InLocker == 1) {
        InLocker = 0
        sprites.destroyAllSpritesOfKind(SpriteKind.Locker)
        sprites.destroyAllSpritesOfKind(SpriteKind.Distraction)
        Lockers()
        sprites.destroy(LockerOverlay)
        MenuOrGame = 1
        Render.moveWithController(2)
        Reginald.setKind(SpriteKind.Prop)
        pause(750)
        Reginald.setKind(SpriteKind.Player)
    }
})
