function Menu () {
    if (SavePoint == 0) {
        story.showPlayerChoices("New Game", "Gallery", "Settings")
    } else {
        story.showPlayerChoices("Continue Game", "Gallery", "Settings")
    }
    if (story.checkLastAnswer("New Game")) {
        game.splash("Arrow Keys = Move")
        game.showLongText("Good luck " + Name + "...", DialogLayout.Bottom)
        blockSettings.writeNumber("MenuOrGame?", 1)
        game.reset()
    } else if (story.checkLastAnswer("Continue Game")) {
        blockSettings.writeNumber("MenuOrGame?", 1)
        game.reset()
    } else if (story.checkLastAnswer("Settings")) {
        story.showPlayerChoices("How To Play", "Reset Save Data", "Back")
        if (story.checkLastAnswer("How To Play")) {
            game.showLongText("Arrow Keys = Move", DialogLayout.Bottom)
            game.showLongText("Hold A/Z = Sprint", DialogLayout.Bottom)
            game.showLongText("B/X = Toggle Torch", DialogLayout.Bottom)
            game.showLongText("Hide in lockers.", DialogLayout.Bottom)
            game.showLongText("Use distractions.", DialogLayout.Bottom)
            game.showLongText("Pull levers.", DialogLayout.Bottom)
            game.showLongText("Good luck.", DialogLayout.Bottom)
            Menu()
        } else if (story.checkLastAnswer("Reset Save Data")) {
            game.showLongText("Are you sure " + Name + "?", DialogLayout.Bottom)
            story.showPlayerChoices("Yes", "No")
            if (story.checkLastAnswer("Yes")) {
                game.showLongText("Alright then, " + Name + ".", DialogLayout.Bottom)
                game.showLongText("Goodbye.", DialogLayout.Bottom)
                blockSettings.clear()
                game.setGameOverMessage(false, "SAVE DATA RESET")
                game.gameOver(false)
            } else if (story.checkLastAnswer("No")) {
                game.showLongText("Good to see you back in your right mind!", DialogLayout.Bottom)
                Menu()
            }
        } else if (story.checkLastAnswer("Back")) {
            Menu()
        }
    } else if (story.checkLastAnswer("Gallery")) {
        Gallery()
    }
}
