scene.onOverlapTile(SpriteKind.Player, assets.tile`myTile70`, function (sprite, location) {
    tiles.replaceAllTiles(assets.tile`myTile70`, assets.tile`transparency16`)
    music.stopAllSounds()
    sprites.destroy(Corruption)
    Hunting = 0
    music.play(music.melodyPlayable(music.bigCrash), music.PlaybackMode.InBackground)
    tiles.setWallAt(tiles.getTileLocation(42, 9), true)
    tiles.setWallAt(tiles.getTileLocation(43, 9), true)
    tiles.setWallAt(tiles.getTileLocation(44, 9), true)
    game.setDialogTextColor(15)
    game.showLongText("Hey " + Name + "!", DialogLayout.Bottom)
    game.showLongText("Don't worry I've closed the door behind you.", DialogLayout.Bottom)
    game.showLongText("Just walk up to the monitor,", DialogLayout.Bottom)
    game.showLongText("and send me the blueprints.", DialogLayout.Bottom)
})
