game.onUpdateInterval(400, function () {
    if (Hunting == 2) {
        scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Reginald)), 92)
    }
})
game.onUpdateInterval(400, function () {
    if (Hunting == 3) {
        if (SavePoint == 2) {
            scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Reginald)), 71)
        } else if (SavePoint == 4) {
            scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Reginald)), 64)
        } else if (SavePoint == 6) {
            scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Reginald)), 62)
        } else if (SavePoint == 8) {
            scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Reginald)), 67)
        } else if (SavePoint == 9) {
            scene.followPath(Corruption, scene.aStar(tiles.locationOfSprite(Corruption), tiles.locationOfSprite(Reginald)), 61)
        }
    }
})
forever(function () {
    pause(5000)
    if (Hunting == 1 && Distracted == 0) {
        RunPathing()
    }
})
forever(function () {
    pause(250)
    if (TorchOn == 0 && hasTorch == 1 && info.score() != 100) {
        info.changeScoreBy(1)
    }
})
forever(function () {
    pause(550)
    if (TorchOn == 1 && hasTorch == 1) {
        info.changeScoreBy(-1)
    }
})
